UPDATE inventory 
SET lock_stock = lock_stock + #{quantity} 
WHERE product_id = #{productId} AND stock - lock_stock >= #{quantity}

UPDATE inventory 
SET lock_stock = lock_stock - #{quantity} 
WHERE product_id = #{productId} AND lock_stock >= #{quantity}

UPDATE inventory 
SET stock = stock - #{quantity}, lock_stock = lock_stock - #{quantity} 
WHERE product_id = #{productId} AND lock_stock >= #{quantity}
